import java.util.Arrays;

public class Solution {
    public static long solve(long[] nums, long k) {
        if (nums.length == 1) {
            return 0;
        }

        Arrays.sort(nums);

        long minRemovals = nums.length - 1; // Worst case: remove all but one

        for (int i = 0; i < nums.length - 1; i++) {
            // Check if the subarray from i to end is balanced
            long min = nums[i];
            long max = nums[nums.length - 1];

            if (max <= min * k) {
                // This subarray is balanced, so we can keep all elements from i to end
                // The number of elements to remove is the elements before i
                minRemovals = Math.min(minRemovals, i);
                break;
            }
        }

        return minRemovals;
    }
}
